from collections import defaultdict

bedrock = boto3.client('bedrock-agent-runtime')

def detect_tool_loop(session_id, trace):
    action_counts = defaultdict(int)
    consecutive_same = 0

    for step in trace.get('trace', []):
        if step.get('type') == 'actionGroupInvocation':
            action_name = step['actionGroup'].get('actionGroupName')
            action_counts[action_name] += 1

            if 'previous_action' in locals():
                if previous_action == action_name:
                    consecutive_same += 1
                    if consecutive_same >= 3:
                        return {'loop_detected': True, 'action': action_name, 'count': consecutive_same}
            previous_action = action_name
    return {'loop_detected': False}

import boto3
from difflib import SequenceMatcher

bedrock = boto3.client('bedrock-agent-runtime')

def detect_kb_loop(session_id, messages):
    kb_queries = []
    for msg in messages:
        if msg.get('type') == 'kbRetrieval':
            query = msg.get('queryText', '')
            kb_queries.append(query)

    for i in range(len(kb_queries)-3):
        if SequenceMatcher(None, kb_queries[i], kb_queries[i+3]).ratio() > 0.9:
            return {
                'loop_detected': True,
                'similarity': SequenceMatcher(None, kb_queries[i], kb_queries[i+3]).ratio(),
                'queries': kb_queries[i:i+4]
            }
    return {'loop_detected': False}

import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

const toolLoopCache = new Map<string, { tool: string; count: number; lastUsed: number }>();

export async function detectToolLoop(sessionId: string, trace: any[]): Promise<boolean> {
  const sessionKey = `loop_${sessionId}`;

  for (const step of trace) {
    if (step.type === 'actionGroupInvocation') {
      const toolName = step.actionGroup.actionGroupName;
      const now = Date.now();

      const cached = toolLoopCache.get(`${sessionKey}_${toolName}`);
      if (cached && (now - cached.lastUsed) < 30000 && cached.count >= 3) {
        return true;
      }

      toolLoopCache.set(`${sessionKey}_${toolName}`, {
        tool: toolName,
        count: (cached?.count || 0) + 1,
        lastUsed: now
      });
    }
  }
  return false;
}

