import { BedrockAgentRuntimeClient } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

const sessionContext = new Map();

export async function invokeAgentWithLoopProtection(
  agentId: string,
  sessionId: string,
  input: string
): Promise<any> {
  const ctx = sessionContext.get(sessionId) || { toolCalls: new Set(), callCount: 0 };

  if (ctx.callCount > 5) {
    return { completion: { finalAnswer: 'Max iterations reached. Task complete.' } };
  }

  const command = new InvokeAgentCommand({
    agentId,
    sessionId,
    inputText: `${input}\nCONTEXT: Tools used: ${Array.from(ctx.toolCalls).join(', ')}`,
    endSession: ctx.callCount > 3
  });

  const result = await client.send(command);
  ctx.callCount++;
  sessionContext.set(sessionId, ctx);

  return result;
}
